packages.code:
generic
   Num_Input_Nodes  : Positive;
   Num_Hidden_Nodes : Natural;
   Num_Output_Nodes : Positive;
   Num_Patterns : Positive;
   Input_To_Output_Connections : Boolean := True;
   Thinning_Active             : Boolean := True;
   Beta : Positive_Real := 0.1;
   P : Positive_Real := 16.0 * Real'Max (Real'Max (Real (Num_Patterns), Real (Num_Input_Nodes) ), Real (Num_Output_Nodes) );
   Q : Positive_Real := 0.25 * P;
   R : Positive_Real := Q;
   S : Positive_Real := 4.0 * P;
   K_P : Natural_Real := 0.0;
   K_Q : Natural_Real := 0.0;
   K_S : Natural_Real := 0.0;
   Ec       : Natural_Real := 0.001;
   Delta_Ec : Natural_Real := 0.001;
   Random_E_Star_Range : Natural_Real := 0.001;
   Random_H_Star_Range : Natural_Real := 0.001;
   with procedure Get_Input (Pattern : in Positive; Input : out Node_Set; Desired : out Node_Set);
package REM_NN
